+		{
+			imagePathList.push_back(path);
+		}
+		else if (
+			suffix == "mp4" ||
+				suffix == "avi" ||
+				suffix == "m4v" ||
+				suffix == "mpeg" ||
+				suffix == "mov" ||
+				suffix == "mkv"
